insert into public.activities (title, description, location_text, location_url, lat, lng, type, age_range, area, cost, vibes, why_its_worth_it, what_to_watch_out_for, tips, nearby_food, start_date, end_date, recurrence, image_url) values

(
  'Great Northern & Cascade Railway',
  'A volunteer-run miniature railway in the tiny mountain town of Skykomish with free rides on 7½-inch gauge scale trains, a small railroad museum in a historic 1898 Great Northern depot, and a gift shop. Ride as many times as you want — it''s the only train museum in the world sitting next to an active mainline railroad.',
  '101 N 5th St, Skykomish, WA 98288',
  'https://maps.google.com/?q=Great+Northern+and+Cascade+Railway+Skykomish',
  47.7096, -121.3614,
  'activity',
  '{"All Ages", "Toddler", "3-5", "5+", "8+"}',
  'Wider PNW',
  'Free',
  '{"Special / Treat", "Chill / Easy", "Outdoor / Nature"}',
  'A genuinely unique find — hand-built scale trains (propane-fired steam, gas, and electric locomotives) running through wooden bridges and tunnels in Depot Park, with the real BNSF mainline right next door so you''ll often see full-size trains roar past while you''re riding. Volunteers run the whole thing, are warm with kids, and love telling stories about the Great Northern era. Rides are free, unlimited, and there''s almost no crowd pressure — on quiet days you can just keep going around. The drive along Highway 2 through the Skykomish River valley is half the experience, especially in fall color.',
  '{"It''s a ~1.5-hour drive from Seattle — not a quick outing, make it a day trip", "Only open Saturdays now (Sundays discontinued due to volunteer shortage) — don''t drive up on a Sunday expecting rides", "Seasonal — train rides run May through October plus some holidays; museum and gift shop are year-round on weekends", "Weather dependent — they don''t run in heavy rain, always check the Facebook page before the drive", "Limited food options in Skykomish itself — plan ahead or combine with a meal at Cascadia Inn", "Donations aren''t required but the operation survives on them — bring some cash"}',
  'Check the railway''s Facebook page the morning of — volunteer schedules and weather can change plans. Grab lunch at Louski''s Deli or Cascadia Inn before or after. Fall (late September through mid-October) is the prettiest time to go for the drive up Highway 2. Kids obsessed with trains will lose their minds — plan on staying longer than you think.',
  '[{"name": "Cascadia Inn", "description": "Historic 1922 inn with a bright cafe and dining room — you can watch the real trains go by from your table"}, {"name": "Louski''s Deli on the Sky", "description": "Sandwiches, soups, pastries — a favorite stop at the gateway to town"}, {"name": "Whistling Post Tavern", "description": "Known for chicken and jojos, cozy local spot"}, {"name": "Pack snacks", "description": "Depot Park has picnic tables and shelter if you''d rather bring your own"}]',
  null, null, 'seasonal',
  'https://b6f0718c6193aa60046d.cdn6.editmysite.com/uploads/b/b6f0718c6193aa60046d291450dcfa47419c6a3030ad24f9b76987550a3ebc91/IMG_3006_1715990528.JPG?width=2400&optimize=medium'
);
